class Solution(object):
    def minRemoval(self, nums, k):
        nums.sort()
        n = len(nums)
        ans = 0
        j = 0
        for i in range(n):
            if j < i:
                j = i
            while j + 1 < n and nums[j + 1] <= k * nums[i]:
                j += 1
            ans = max(ans, j - i + 1)
        return n - ans
